import * as React from "react";
import { useDashboardData } from "./data/data-provider";

/**
 * Onglet "Mon rythme" — orchestre :
 *   .rhythm-top : Timeline (3 semaines) + annotations + légende
 *   .rhythm-bottom : Carte IRA (1/3) | Leviers (2.2/6) | Panel conseil (1.7/6)
 *
 * En cours d'assemblage (Phases 5-9).
 */
export const RythmeTab: React.FC = () => {
  const data = useDashboardData();
  return (
    <div>
      <p style={{ fontFamily: "DM Sans", color: "var(--on-surface-muted)" }}>
        Onglet Rythme — référence : {data.referenceDate}
        <br />
        Semaines chargées : {data.weeks.map((w) => `S${w.weekNumber}`).join(" · ")}
        <br />
        Score IRA : <strong>{data.ira.value}</strong> ({data.ira.label}, Δ{data.ira.delta})
        <br />
        Annotations : {data.annotations.length}
      </p>
    </div>
  );
};
