import * as React from "react";
import { createRoot } from "react-dom/client";
import { FluentProvider, webLightTheme } from "@fluentui/react-components";
import * as microsoftTeams from "@microsoft/teams-js";
import DashboardApp from "./DashboardApp";

/**
 * Point d'entrée du dashboard Gr33t — exposé via une Teams/M365 App
 * (staticTab dans le manifest Teams). Ne dépend PAS d'Office.js, mais
 * du Teams SDK pour l'auth et le contexte utilisateur.
 */

async function bootstrap() {
  try {
    await microsoftTeams.app.initialize();
    // Notifie Teams que l'app a fini de charger → retire le loader
    microsoftTeams.app.notifySuccess();
  } catch (err) {
    // Hors contexte Teams (ex: ouverture directe dans un navigateur) — on
    // continue quand même en mode dégradé.
    // eslint-disable-next-line no-console
    console.warn("[dashboard] Teams SDK init failed:", err);
  }

  const container = document.getElementById("container");
  if (!container) throw new Error("Missing #container");
  const root = createRoot(container);
  root.render(
    <FluentProvider theme={webLightTheme}>
      <DashboardApp />
    </FluentProvider>
  );
}

void bootstrap();
